    """Sorted names of nodes at most 'depth' hops from start of an edge-list graph."""
    start = spec["start"]; cap = spec["depth"]
    adj = {}
    for u, v in spec["edges"]:
        adj.setdefault(u, []).append(v)
    depth = {start: 0}; queue = [start]; i = 0
    while i < len(queue):
        n = queue[i]; i += 1
        if depth[n] < cap:
            for t in adj.get(n, []):
                if t not in depth:
                    depth[t] = depth[n] + 1
                    queue.append(t)
    return sorted(depth.keys())

