        if n in road_seen:
            continue
        road_seen.add(n)
        if n in road_adj:
            stack.extend(road_adj[n])
    rail_seen = set()
    stack = [spec["start"]]
    while stack:
        n = stack.pop()
        if n in rail_seen:
            continue
        rail_seen.add(n)
        if n in rail_adj:
